package com.hogaria.entity;
import jakarta.persistence.*;import java.math.BigDecimal;import java.time.LocalDateTime;import java.util.UUID;import lombok.*;
@Entity @Table(name="budget_category_item") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder
public class BudgetCategoryItem { @Id @GeneratedValue private UUID id; @Column(name="budget_month_id",nullable=false) private UUID budgetMonthId; @Column(name="category_id",nullable=false) private UUID categoryId; @Column(name="budget_amount",nullable=false) private BigDecimal budgetAmount; @Column(name="created_at",nullable=false) private LocalDateTime createdAt; @Column(name="updated_at",nullable=false) private LocalDateTime updatedAt; @PrePersist void pp(){var n=LocalDateTime.now(); if(createdAt==null)createdAt=n; if(updatedAt==null)updatedAt=n;} @PreUpdate void pu(){updatedAt=LocalDateTime.now();}}
